VALUES
  ('heelevel3-7c4986e7-moex-00205', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司 X1 年 1 月 1 日取得主管機關之研究發展補助款$500,000，此補助款係供該公司未來 之產品開發計畫，預期研究發展支出於未來5年內平均發生，並且X1年度之研究發展支出 共$300,000，公司估計研究發展總支出為$1,500,000。請問X1年度之政府補助款$500,000應 認列為「政府補助之利益」之金額為：', '["$100,000", "$250,000", "$300,000", "$500,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00206', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司普通股流通股數相關資訊如下： X1年1月1日流通在外股數 2,500,000股 X1年4月1日按市價現金增資發行普通股 400,000股 X1年7月1日購回庫藏股 150,000股 X2年度2月1日發放100%股票股利 假設X1年度財報核准公布日為X2年3月15日，則計算X1年基本每股盈餘時，所使用之 普通股流通在外加權平均股數為何？', '["2,725,000股", "2,750,000股", "3,650,000股", "5,450,000股"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00207', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '在綜合損益表中，當收益和費損的項目重要時，企業應單獨揭露其性質和金額。下列需要單', '["沖減存貨至淨變現價值，或沖減不動產、廠房及設備至 可回收金額（亦即認列資產減損損失），以及該沖減的迴轉（亦即認列減損損失的迴轉利益）", "企業活動的重組損失，以及重組成本負債準備的迴轉（重組損失迴轉利益）", "處分不動 產、廠房及設備項目的損益", "處分投資的損益 ⑤停業單位損益 ⑥無聊的訴訟，估計敗 訴的機率微乎其微（Remote） ⑦其他之負債準備迴轉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00208', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司111年5月1日收到客戶開立之票據一張，面額為$240,000，利率4%，5個月到期。', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00209', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '年 7 月 1 日公司以此票據向乙銀行貼現，貼現率 7%，若該票據貼現視為無追索權之出 售，則票據貼現損失金額與下列那項答案最接近（答案四捨五入至元）？', '["$412", "$1,218", "$1,612", "$1,870"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 111, "answer_corrected": false, "flags": ["answer_missing"], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00210', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司自110年開始營業，其存貨相關資料如下： 110年 111年 期末存貨–採先進先出法 $4,700,000 $5,100,000 採加權平均法 $4,100,000 $4,300,000 若稅率為20%，則111年底先進先出法之保留盈餘比加權平均法：', '["少$150,000", "多$640,000", "多$150,000", "少$640,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00211', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於109年1月1日購入乙公司發行的公司債，面額$100,000，票面利率5%，每年12 月31日付息，112年12月31日到期。109年1月1日按$103,480價格加計$205手續費購 入，當日有效利率4%，分類為透過其他綜合損益按公允價值衡量之金融資產。109年12月 31日，當日該債券之公允價值為$105,000。請問109年12月31日「透過其他綜合損益按公 允價值衡量之債務工具投資評價調整」的金額與下列那項答案最接近（答案四捨五入至元）？', '["$2,168", "$2,618", "$4,567", "$6,234"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00212', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年1月1日以$10,000買進乙公司30%之股權並取得重大影響力，乙公司的淨資 產為$40,000，而甲公司取得之股權份額之公允價值亦為$12,000。請問甲公司當日應增加「採 用權益法之投資」科目之金額為：', '["$3,000", "$10,000", "$12,000", "$40,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00213', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '下列有幾項資產分類為「待出售」後，不適用IFRS5號公報以「帳面金額與公允價值減出售', '["遞延所得稅資產", "由員工福利產生的資產", "不動產、廠房 及設備", "金融工具規範的金融資產 ⑤採用公允價值模式處理的投資性不動產 ⑥農業會 計採用公允價值減出售成本後餘額衡量的非流動資產"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
  ('heelevel3-7c4986e7-moex-00214', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-e0b1f2ed', 'sub-heelevel3-7c4986e7-02', NULL, 'single_choice', '甲公司於110年初購入100頭3個月大之乳牛，每頭乳牛價格為$5,000與支付運費$20,000， 準備飼養成熟後生產牛奶。甲公司估計若立即將 100 頭乳牛出售，應支付送至市場之運費 $22,000 及市場管理規費$8,000。甲公司 110 年間耗費草料費用$120,000，人工飼育成本 $130,000，公司將後續支出作為費用處理。110年底公司估計若將100頭乳牛立即出售，每頭 售價為$10,000，另應支付運送牛隻至市場之運費$32,000及市場管理規費等$8,000，則甲公司 110年上述交易與年底評價相關分錄與科目何者正確？', '["購入乳牛時，應借記「生產性生物資產」$480,000", "購入乳牛時，應借記「公允價值減出售成本之變動損益」$20,000", "年底「公允價值減出售成本之變動損益」貸方餘額$440,000", "年底評價時應貸記「公允價值減出售成本之變動損益」$510,000 32270"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "b22243a271d1", "answer_pdf_sha1": "39d04e008c92", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL)
